import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — base premiums and the processing fee
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single plain sword, newcomer, first contract → premium 115 G (100 base + 10 first + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single amulet (plain), newcomer, first contract → premium 71 G (60 + 6 first = 66, +5 fee = 71)");
  it.todo("single staff (plain), newcomer, first contract → premium 93 G (80 + 8 first + 5 fee)");
  it.todo("single potion (plain), newcomer, first contract → premium 49 G (40 + 4 first + 5 fee)");

  // Components and blocks
  it.todo("2 runes → 55 G (50 base + 5 fee)");
  it.todo("3 runes → 65 G (60 base block + 5 fee)");
  it.todo("4 runes → 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes → 180 G (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone → 80 G (75 base + 5 fee, no block since different types)");
  it.todo("3 runes + 3 moonstones → 125 G (120 base, two separate blocks + 5 fee)");

  // Item-specific modifiers
  it.todo("cursed sword (newcomer, 0 years, first contract) → 165 G (100 + 50 curse + 10 first = 160 + 5 fee)");
  it.todo("cursed sword with enchantment 5 (newcomer, first contract) → premium includes 50% curse + 30% high-enchantment");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies");

  // Policy-wide modifiers
  it.todo("cursed sword + plain amulet on multi-item policy: curse surcharge applies only to cursed item base");
  it.todo("long-standing customer (2 years) gets 20% loyalty discount");
  it.todo("second contract gets 15% follow-up discount; first insurance still applies per item");
  it.todo("long-standing customer's second contract with cursed enchanted sword → 160 G (integration)");

  // Rounding in MHPCO's favor
  it.todo("premium with fractional 197.5 G rounds up to 198 G");

  // Errors
  it.todo("unknown item type causes CLI/scenario to error");

  // Claim — base reimbursement
  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 deductible)");
  it.todo("rune damage 200 G → payout 100 G");
  it.todo("high-enchantment item (>=8) damage → 50% then deductible");
  it.todo("dragon-material sword damage → full reimbursement then deductible");
  it.todo("dragon-material sword with enchantment 9 → 50% rule wins, then deductible");
  it.todo("dragon-material sword with enchantment 5, damage 800 → payout 700");
  it.todo("steel sword with enchantment 9, damage 1000 → payout 400");
  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 → payout 400");

  // Deductible per damage event
  it.todo("dragon attack on sword (500) and amulet (300): payout 600 (deductible per item)");

  // Cap on payouts
  it.todo("policy cap is 2× insurance sum based on unmodified insurance values");
  it.todo("two successive claims drain the cap: 1500 then 1500 on sword → 1400 then 600");
  it.todo("block discount does not affect insurance sum (sword + 3 runes → insurance sum 1750)");

  // Multiple items of same type
  it.todo("policy with two swords: insurance sum 2000, cap 4000; two sword damages → each gets own deductible");
  it.todo("damages array with more entries of a type than the policy covers → CLI error");

  // Claim errors
  it.todo("claim references item not on the policy → CLI error");
  it.todo("claim with negative damage amount → CLI error");

  // Payout rounding
  it.todo("payout with fractional 350.5 G rounds down to 350 G");
});

