export interface Customer {
  yearsWithMHPCO: number;
}

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export type Step = QuoteStep | ClaimStep;

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: { cause?: string; damages: Damage[] };
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Damage {
  itemType: string;
  amount: number;
}

export type Result = { premium: number } | { payout: number; remainingCap: number };

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;

export function runScenario(scenario: Scenario): { results: Result[] } {
  const results: Result[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      // Group items: separate non-components from components by type.
      const componentCounts: Record<string, number> = {};
      const mainItems: Item[] = [];
      for (const item of step.items) {
        if (COMPONENT_TYPES.has(item.type)) {
          componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
        } else {
          mainItems.push(item);
        }
      }
      let policyBase = 0;
      for (const item of mainItems) {
        const base = BASE_PREMIUMS[item.type] ?? 0;
        policyBase += base + base * 0.1;
      }
      for (const count of Object.values(componentCounts)) {
        const base = count === 3 ? 60 : count * COMPONENT_BASE;
        policyBase += base + base * 0.1;
      }
      return { premium: Math.ceil(policyBase + 5) };
    }
    return { premium: 5 };
  });
  return { results };
}

